import json

# Get the paper titles list directly from the previous result 
# (it's stored as a variable, not a file path)
paper_titles_result = locals().get('var_functions.execute_python:26', '')
if isinstance(paper_titles_result, dict):
    titles_2016_pa = paper_titles_result.get('titles', [])
else:
    titles_2016_pa = []

# Get citation data
citation_result = locals().get('var_functions.query_db:48', '')
if isinstance(citation_result, list):
    activity_citations = citation_result
else:
    activity_citations = []

# Create matching results
paper_dict = {}
for title in titles_2016_pa:
    paper_dict[title] = 0

# Match papers with their citations
for item in activity_citations:
    title = item.get('title', '')
    total = int(item.get('total', 0))
    if title in paper_dict:
        paper_dict[title] = total

# Build final results
results = []
for title, citations in paper_dict.items():
    if citations > 0:
        results.append({'title': title, 'total_citations': citations})

# Sort by citation count
def get_citations(paper):
    return paper.get('total_citations', 0)

results.sort(key=get_citations, reverse=True)

# Prepare output
output = {
    'papers': results,
    'count_with_citations': len(results),
    'total_papers': len(titles_2016_pa)
}

print('__RESULT__:')
print(json.dumps(output))

